mapper.select:
SELECT f.id, f.user_id, f.item_id, f.news_id, f.type, f.created_at, i.id as item_pk, i.name as item_name, i.name_cn as item_name_cn, i.icon_url as item_icon_url, i.buff_price as item_buff_price, i.rarity as item_rarity, n.id as news_pk, n.title as news_title, n.summary as news_summary, n.cover_image as news_cover_image, n.category as news_category, n.author as news_author, n.views as news_views, n.created_at as news_created_at FROM sys_favorite f LEFT JOIN item i ON f.item_id = i.id AND f.type = 1 LEFT JOIN sys_news n ON f.news_id = n.id AND f.type = 2 WHERE f.user_id = #{userId}
AND f.type = #{type}
ORDER BY f.created_at DESC

